这是一个非常清晰的错误。`smolagents` 的 Memory 列表里的第一个元素通常是 `TaskStep`（只包含用户输入的任务），而不是 `ActionStep`。`TaskStep` 对象确实没有 `model_output_message` 属性。

我们需要修改 `_save_trajectory` 函数，根据 step 的类型（是 `TaskStep` 还是 `ActionStep`）来分别处理。

请用下面的代码**完全替换**你 `agent_runner.py` 中的 `_save_trajectory` 方法。

### 修复后的 `_save_trajectory`

主要改动：
1.  使用 `getattr(step, "...", None)` 安全访问属性，不再直接点号访问。
2.  专门处理 Step 0 (通常是 `TaskStep`)，从中提取 User Message。
3.  跳过没有 `model_output_message` 的 Step (防止报错)。

```python
    def _save_trajectory(self, agent, task_info, output_dir):
        """生成并保存 ReAct 格式的对话轨迹 (修复 AttributeError)"""
        import json
        import os
        import sys
        import traceback

        print("\n[TRAJ DEBUG] Starting to save trajectory...", file=sys.stderr)

        try:
            # 1. 准备 Tools 定义
            tools_list = []
            try:
                # 兼容 agent.tools 是 dict 或 ToolCollection 的情况
                tools_source = agent.tools
                if hasattr(tools_source, "values"):
                    iterator = tools_source.values()
                else:
                    iterator = tools_source # 假设是 list

                for tool in iterator:
                    tool_def = {
                        "type": "function",
                        "function": {
                            "name": getattr(tool, "name", "unknown"),
                            "description": getattr(tool, "description", ""),
                            "parameters": getattr(tool, "inputs", {}) 
                        }
                    }
                    tools_list.append(tool_def)
            except Exception as e:
                print(f"[TRAJ DEBUG] Warning: Failed to serialize tools: {e}", file=sys.stderr)
                tools_list = [{"error": "serialization_failed"}]

            # 2. 构建 Messages 列表
            messages = []

            # --- System Prompt ---
            try:
                sys_content = getattr(agent, "system_prompt", "System prompt not available")
                messages.append({"role": "system", "content": sys_content})
            except:
                pass

            # --- 遍历 Steps ---
            steps = agent.memory.steps
            print(f"[TRAJ DEBUG] Processing {len(steps)} steps...", file=sys.stderr)

            for i, step in enumerate(steps):
                step_type = type(step).__name__
                # print(f"[TRAJ DEBUG] Processing Step {i} ({step_type})", file=sys.stderr)

                # === Case A: TaskStep (通常是第一个 Step，包含用户任务) ===
                if step_type == "TaskStep" or hasattr(step, "task"):
                    task_content = getattr(step, "task", "")
                    if task_content:
                        messages.append({"role": "user", "content": str(task_content)})
                    continue # TaskStep 处理完就跳过，因为它没有 model output

                # === Case B: ActionStep (包含模型思考、工具调用、工具结果) ===

                # 1. 提取 Assistant Output (Model Output Message)
                # 使用 getattr 安全获取，防止 AttributeError
                assistant_msg = getattr(step, "model_output_message", None)

                if assistant_msg:
                    # 获取内容
                    content = getattr(assistant_msg, "content", "")
                    reasoning = getattr(assistant_msg, "reasoning_content", None)

                    msg_dict = {"role": "assistant"}

                    # 按照格式要求处理 Thinking
                    if reasoning:
                        msg_dict["reasoning_content"] = reasoning
                        msg_dict["content"] = content
                    else:
                        msg_dict["reasoning_content"] = content
                        msg_dict["content"] = None # 纯工具调用时 content 可能不需要

                    # 处理 Tool Calls
                    tool_calls = getattr(assistant_msg, "tool_calls", [])
                    if tool_calls:
                        tc_list = []
                        for tc in tool_calls:
                            func = getattr(tc, "function", None)
                            if func:
                                func_name = getattr(func, "name", "unknown")
                                func_args = getattr(func, "arguments", "{}")

                                # 确保 arguments 是字符串格式的 JSON
                                if isinstance(func_args, dict):
                                    func_args_str = json.dumps(func_args, ensure_ascii=False)
                                else:
                                    func_args_str = str(func_args)

                                tc_list.append({
                                    "function": {
                                        "name": func_name,
                                        "arguments": func_args_str
                                    }
                                })
                        msg_dict["tool_calls"] = tc_list

                    messages.append(msg_dict)

                # 2. 提取 Tool Outputs (Observations)
                # 优先检查 step_tool_outputs (我们在 agents.py 里修改加入的)
                step_tool_outputs = getattr(step, "step_tool_outputs", None)

                if step_tool_outputs:
                    for tool_out in step_tool_outputs:
                        messages.append({
                            "role": "tool",
                            # 你的格式里 tool role 好像没有 name 字段，如果有需要可以加
                            "content": str(getattr(tool_out, "output", "")) 
                        })
                else:
                    # 回退方案：使用 observations 属性
                    observations = getattr(step, "observations", None)
                    if observations:
                        messages.append({
                            "role": "tool",
                            "content": str(observations)
                        })

            # 3. 最终组装
            traj_data = {
                "traj_type": "conversation",
                "task_info": {
                    "env_id": task_info.get("env_id", "unknown"),
                    "task_id": task_info.get("task_id", "unknown"),
                    "task": task_info.get("task") or task_info.get("description", "")
                },
                "tools": json.dumps(tools_list, ensure_ascii=False),
                "messages": json.dumps(messages, ensure_ascii=False),
                "steps": len(steps)
            }

            # 4. 写入文件
            task_id = task_info.get("task_id", "unknown")
            os.makedirs(output_dir, exist_ok=True)
            traj_file = os.path.join(output_dir, f"{task_id}_traj.json")

            with open(traj_file, 'w', encoding='utf-8') as f:
                json.dump(traj_data, f, indent=2, ensure_ascii=False)

            print(f"[TRAJ DEBUG] ✓ Successfully saved trajectory to {traj_file}", file=sys.stderr)

        except Exception as e:
            print(f"\n[TRAJ ERROR] ❌ Failed to save trajectory: {e}", file=sys.stderr)
            traceback.print_exc()
```

### 关键修复点说明

1.  **`step_type` 判断**：我加了 `if step_type == "TaskStep" or hasattr(step, "task"):`。这会识别列表中的第一个步骤（用户提问），它没有 `model_output_message`，所以我们只提取 `step.task` 作为 `role: user` 的消息。
2.  **`getattr` 安全访问**：对于所有可能不存在的属性（如 `model_output_message`, `tool_calls`），全部改用 `getattr(obj, "attr", default)`。这样即使 `smolagents` 版本不同或者步骤结构不同，也不会直接 Crash。

运行此代码，应该就能成功生成 JSON 文件了。
